        "sourceLabel": "Volo's Guide to Monsters",
        "savingThrows": "Int +9, Wis +8, Cha +9",
        "skills": "Arcana +9, Insight +8, Perception +8, Stealth +5 enses darkvision 120 ft., passive Perception 18",
        "damageVulnerabilities": "",
        "damageResistances": "",
